@Override
public DTO save(DTO dto) {
    if(usersRepo.existsByUserId(dto.getUserId())) {
        Entity entity = mapper.map(dto, Entity.class);
        return mapper.map(repo.save(entity), DTO.class);
    }
}

public List<DTO> retrieve(String agntNbr, String entpsId) {
    boolean hasAgntNbr = StringUtils.hasText(agntNbr);
    if(hasAgntNbr && agntNbr.contains("*")) {
        return repo.findByAgntNbrLike(agntNbr.replace("*", "%"));
    }
}

public List<DTO> retrieveAll() {
    List<Entity> list = repo.findAll();
    return mapper.map(list, new TypeToken<List<DTO>>(){}.getType());
}

@Transactional
public void deleteAll(List<Long> ids) {
    ids.forEach(id -> repo.deleteById(id));
}

public DTO save(DTO dto) {
    if(!repo.findByKeys(dto.getContractAgentNumber()).isEmpty()) {
        throw new R2BContractAgentException("Already exists");
    }
    return mapper.map(repo.save(mapper.map(dto, Entity.class)), DTO.class);
}

