protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain chain) {
    String userId = request.getHeader("X-User-Id");
    if(userId != null) {
        ApplicationUsers user = userService.getUserById(userId);
        // Set authentication...
    }
}

private void setDetails(HttpServletRequest request, HttpServletResponse response, UsernamePasswordAuthenticationToken auth) {
    auth.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
    SecurityContextHolder.getContext().setAuthentication(auth);
}

@Override
public void doFilter(ServletRequest req, ServletResponse res, FilterChain chain) {
    response.setHeader("Access-Control-Allow-Origin", "*");
    if("OPTIONS".equals(request.getMethod())) {
        response.setStatus(200);
    } else {
        chain.doFilter(req, res);
    }
}

@Bean
public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
    return http.sessionManagement(s -> s.sessionCreationPolicy(STATELESS))
        .csrf(AbstractHttpConfigurer::disable)
        .authorizeHttpRequests(auth -> auth.anyRequest().authenticated())
        .addFilterBefore(userFilter(), UsernamePasswordAuthenticationFilter.class)
        .build();
}

@Bean
public PasswordEncoder passwordEncoder() {
    return new BCryptPasswordEncoder();
}

@Bean
ModelMapper mapper() {
    return new ModelMapper();
}

@ExceptionHandler(AlreadyExistException.class)
public ResponseEntity<ErrorResponseDTO> handleAlreadyExists(AlreadyExistException e) {
    return ResponseEntity.status(HttpStatus.CONFLICT).body(new ErrorResponseDTO(LocalDateTime.now(), e.getMessage(), "Already Exists"));
}

@ExceptionHandler(NotFoundException.class)
public ResponseEntity<ErrorResponseDTO> handleNotFound(NotFoundException e) {
    return ResponseEntity.status(HttpStatus.NOT_FOUND).body(new ErrorResponseDTO(LocalDateTime.now(), e.getMessage(), "Not Found"));
}

@ExceptionHandler(NoResourceFoundException.class)
public ResponseEntity<ErrorResponseDTO> handleNoResource(NoResourceFoundException e) {
    return ResponseEntity.status(HttpStatus.NOT_FOUND).body(new ErrorResponseDTO(LocalDateTime.now(), e.getMessage(), "URL not found"));
}

@ExceptionHandler(Exception.class)
public ResponseEntity<ErrorResponseDTO> handleException(Exception e) {
    return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(new ErrorResponseDTO(LocalDateTime.now(), e.getMessage(), "Internal Error"));
}

public static void main(String[] args) {
    SpringApplication.run(EssOdadminServiceApplication.class, args);
}
